import React, { useEffect, useState } from 'react';
import axios from 'axios';
import {
  Container,
  TextField,
  MenuItem,
  Button,
  Typography,
  Paper,
  Box
} from '@mui/material';

function Cadastro() {
  const [clinics, setClinics] = useState([]);

  const [form, setForm] = useState({
    clinic_id: '',
    city: '',
    state: '',
    region: '',
    patient_name: '',
    patient_phone: '',
    channel: '',
    service_type: '',
    criticality: 'media',
    description: '',
    file: null
  });

  // 🔥 BUSCAR CLÍNICAS
  useEffect(() => {
    axios.get('http://localhost:3001/clinics')
      .then(res => {
        console.log("CLINICAS:", res.data);
        setClinics(res.data);
      })
      .catch(err => console.error(err));
  }, []);

  // 🔥 SELEÇÃO DE CLÍNICA
  const handleClinicChange = (id) => {
    const clinic = clinics.find(c => c.id === parseInt(id));

    if (clinic) {
      setForm(prev => ({
        ...prev,
        clinic_id: clinic.id,
        city: clinic.city || '',
        state: clinic.state || '',
        region: clinic.region || ''
      }));
    }
  };

  // 🔥 SUBMIT
  const handleSubmit = async () => {
    try {
      const formData = new FormData();

      Object.keys(form).forEach(key => {
        formData.append(key, form[key]);
      });

      await axios.post('http://localhost:3001/complaints', formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });

      alert('Reclamação salva com sucesso!');

      // 🔄 LIMPAR FORM
      setForm({
        clinic_id: '',
        city: '',
        state: '',
        region: '',
        patient_name: '',
        patient_phone: '',
        channel: '',
        service_type: '',
        criticality: 'media',
        description: '',
        file: null
      });

    } catch (error) {
      console.error(error);
      alert('Erro ao salvar');
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper sx={{ p: 4, mt: 5, borderRadius: 3 }}>

        <Typography variant="h5" gutterBottom>
          Cadastro de Reclamação
        </Typography>

        {/* CLÍNICA */}
        <TextField
          select
          label="Clínica"
          fullWidth
          margin="normal"
          value={form.clinic_id}
          onChange={(e) => handleClinicChange(e.target.value)}
        >
          {clinics.map(c => (
            <MenuItem key={c.id} value={c.id}>
              {c.name}
            </MenuItem>
          ))}
        </TextField>

        {/* LOCALIZAÇÃO */}
        <TextField label="Cidade" value={form.city} fullWidth disabled margin="normal" />
        <TextField label="Estado" value={form.state} fullWidth disabled margin="normal" />
        <TextField label="Região" value={form.region} fullWidth disabled margin="normal" />

        {/* PACIENTE */}
        <TextField
          label="Nome do paciente"
          fullWidth
          margin="normal"
          value={form.patient_name}
          onChange={(e) => setForm({ ...form, patient_name: e.target.value })}
        />

        <TextField
          label="Telefone"
          fullWidth
          margin="normal"
          value={form.patient_phone}
          onChange={(e) => setForm({ ...form, patient_phone: e.target.value })}
        />

        {/* CANAL */}
        <TextField
          select
          label="Canal"
          fullWidth
          margin="normal"
          value={form.channel}
          onChange={(e) => setForm({ ...form, channel: e.target.value })}
        >
          <MenuItem value="whatsapp">WhatsApp</MenuItem>
          <MenuItem value="email">Email</MenuItem>
          <MenuItem value="google">Google</MenuItem>
          <MenuItem value="facebook">Facebook</MenuItem>
          <MenuItem value="instagram">Instagram</MenuItem>
          <MenuItem value="nps">NPS</MenuItem>
        </TextField>

        {/* SERVIÇO */}
        <TextField
          select
          label="Tipo de serviço"
          fullWidth
          margin="normal"
          value={form.service_type}
          onChange={(e) => setForm({ ...form, service_type: e.target.value })}
        >
          <MenuItem value="clinico">Clínico Geral</MenuItem>
          <MenuItem value="ortodontia">Ortodontia</MenuItem>
          <MenuItem value="implante">Implante</MenuItem>
          <MenuItem value="endodontia">Endodontia</MenuItem>
        </TextField>

        {/* CRITICIDADE */}
        <TextField
          select
          label="Criticidade"
          fullWidth
          margin="normal"
          value={form.criticality}
          onChange={(e) => setForm({ ...form, criticality: e.target.value })}
        >
          <MenuItem value="baixa">Baixa</MenuItem>
          <MenuItem value="media">Média</MenuItem>
          <MenuItem value="alta">Alta</MenuItem>
        </TextField>

        {/* DESCRIÇÃO */}
        <TextField
          label="Descrição"
          multiline
          rows={4}
          fullWidth
          margin="normal"
          value={form.description}
          onChange={(e) => setForm({ ...form, description: e.target.value })}
        />

        {/* 🔥 UPLOAD */}
        <Box mt={2}>
          <Typography variant="body2">Anexar evidência</Typography>
          <input
            type="file"
            onChange={(e) =>
              setForm({ ...form, file: e.target.files[0] })
            }
          />
        </Box>

        {/* BOTÃO */}
        <Box mt={3}>
          <Button fullWidth variant="contained" onClick={handleSubmit}>
            SALVAR
          </Button>
        </Box>

      </Paper>
    </Container>
  );
}

export default Cadastro;
